  if (!parsed.success) {
    return res.status(400).json({ error: 'Invalid user id' });
  }
  // ... lookup logic
  res.json({ id: parsed.data.id, name: 'Alice' });
});

app.get('/users', requireAuth, (_req, res) => {
  res.json([
    { id: 1, name: 'Alice' },  // drop email unless caller is authorized
    { id: 2, name: 'Bob' },
  ]);
});

