app.use(helmet());                           // secure headers
app.use(express.json({ limit: '10kb' }));    // explicit small body limit

// --- Rate limiting ---
app.use(rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
}));

// --- Validation helper ---
