  '/users/:id',
  param('id').isInt({ min: 1, max: 1_000_000 }).toInt(),
  handleValidation,
  (req, res, next) => {
    try {
      const { id } = req.params;
      // ...lookup logic
      res.json({ id, name: 'Alice' });
    } catch (err) {
      next(err);
    }
  }
