const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const { body, param, validationResult } = require('express-validator');

const app = express();

// --- Security middleware ---
app.disable('x-powered-by');
app.use(helmet());
app.use(express.json({ limit: '10kb' })); // cap body size
app.use(rateLimit({ windowMs: 60_000, max: 100 }));

// --- Validation helper ---
const validate = (req, res, next) => {
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    return res.status(400).json({ error: 'Invalid input' }); // don't echo input
  }
  next();
};

// --- Routes ---
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get(
  '/users/:id',
  param('id').isInt({ min: 1, max: 2_147_483_647 }).toInt(),
  validate,
  (req, res, next) => {
    try {
      // lookup by validated req.params.id
      res.json({ id: req.params.id });
    } catch (err) {
      next(err);
    }
  }
);

// --- 404 + error handlers (must be last) ---
app.use((req, res) => res.status(404).json({ error: 'Not found' }));

app.use((err, req, res, _next) => {
  // Log full error internally, return generic message externally
  console.error({ msg: 'request_error', err: err.message, stack: err.stack });
  res.status(err.status || 500).json({ error: 'Internal server error' });
});

// --- Process-level safety ---
process.on('unhandledRejection', (reason) => {
  console.error({ msg: 'unhandled_rejection', reason });
});
process.on('uncaughtException', (err) => {
  console.error({ msg: 'uncaught_exception', err: err.message });
  process.exit(1);
});

// --- Startup with env config + graceful shutdown ---
const PORT = Number(process.env.PORT) || 3000;
if (!Number.isInteger(PORT) || PORT < 1 || PORT > 65535) {
  throw new Error('Invalid PORT');
}

const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

for (const sig of ['SIGTERM', 'SIGINT']) {
  process.on(sig, () => server.close(() => process.exit(0)));
}

module.exports = app;
```

---

## Summary of Security Improvements

| Area | Change | Why |
|---|---|---|
| Headers | `helmet()`, disable `x-powered-by` | Mitigates XSS, clickjacking, fingerprinting |
| DoS | `rateLimit`, `json({ limit })` | Prevents abuse and payload-based DoS |
| Input | `express-validator` with whitelists | Rejects malformed/malicious input before handlers |
| Errors | Central error middleware, generic messages | Prevents stack-trace/info leaks |
| Process | `unhandledRejection`/`uncaughtException` handlers | Avoids silent failures |
| Shutdown | `SIGTERM`/`SIGINT` → `server.close` | Drains in-flight requests cleanly |
| Config | `PORT` from env with bounds check | Avoids hardcoded/invalid values |
| Logging | Structured logs, no input echo | Reduces log-injection & secret-leak risk |

