const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const { z } = require('zod'); // or joi / express-validator

const app = express();
const PORT = Number(process.env.PORT) || 3000;
const isProd = process.env.NODE_ENV === 'production';

// --- Security middleware ---
app.disable('x-powered-by');
app.use(helmet());
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

app.use(rateLimit({
  windowMs: 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
}));

// --- Routes ---
app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// Example: validate a query param with a schema
const listUsersSchema = z.object({
  limit: z.coerce.number().int().min(1).max(100).default(10),
});

app.get('/users', (req, res, next) => {
  try {
    const { limit } = listUsersSchema.parse(req.query);
    const users = [
      { id: 1, name: 'Alice' },
      { id: 2, name: 'Bob' },
    ].slice(0, limit);
    res.json(users); // don't leak emails by default
  } catch (err) {
    next(err);
  }
});

// --- 404 + error handler (must be last) ---
app.use((_req, res) => res.status(404).json({ error: 'Not found' }));

app.use((err, _req, res, _next) => {
  const status = err.status || (err.name === 'ZodError' ? 400 : 500);
  const body = { error: status === 500 ? 'Internal server error' : err.message };
  if (!isProd && status === 500) body.stack = err.stack;
  res.status(status).json(body);
});

