const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();
app.disable('x-powered-by');
app.use(helmet());
app.use(express.json({ limit: '10kb' }));
app.use(rateLimit({ windowMs: 60_000, max: 100 }));

app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  res.json([
    { id: 1, name: 'Alice' },
    { id: 2, name: 'Bob' },
  ]);
});

app.use((req, res) => res.status(404).json({ error: 'Not Found' }));
app.use((err, req, res, next) => {
  console.error(err);
  res.status(err.status || 500).json({ error: 'Internal Server Error' });
});

const port = process.env.PORT || 3000;
const server = app.listen(port, () => console.log(`Server on ${port}`));
process.on('SIGTERM', () => server.close(() => process.exit(0)));

module.exports = app;
```

## Priority Order

1. **Critical:** global error handler, 404 handler, `helmet`, disable `x-powered-by`.
2. **High:** rate limiting, body-size limit, graceful shutdown, env-driven port.
3. **Medium:** schema validation library in place before adding any input-accepting route, CORS allowlist, structured logger.
4. **Ongoing:** treat PII deliberately; add auth before exposing user data.

