const userQuery = z.object({
  limit: z.coerce.number().int().min(1).max(100).default(20),
  cursor: z.string().regex(/^[A-Za-z0-9_-]+$/).optional(),
});

app.get('/users', (req, res, next) => {
  const parsed = userQuery.safeParse(req.query);
  if (!parsed.success) return res.status(400).json({ error: parsed.error.flatten() });
  // ...
});
```

Additionally, before parsing JSON bodies, bound the payload size: `app.use(express.json({ limit: '100kb' }))`.

## 3. Missing security middleware

At minimum, add:

```js
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const cors = require('cors');

app.disable('x-powered-by');                // hides Express fingerprint
app.use(helmet());                          // sane default security headers
app.use(cors({ origin: ALLOWLIST }));       // never use `*` with credentials
app.use(rateLimit({ windowMs: 60_000, max: 100 }));
```

## 4. PII exposure in `/users`

`/users` returns email addresses with no authentication, authorization, or pagination. Even with mock data this sets a bad pattern. Gate it behind auth middleware and return only fields the caller is entitled to:

```js
