const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const { query, validationResult } = require('express-validator');

const app = express();

// --- Security middleware ---
app.disable('x-powered-by');
app.use(helmet());
app.use(express.json({ limit: '10kb' })); // prevent large-body DoS
app.use(rateLimit({ windowMs: 60_000, max: 100 }));

// --- Validation helper ---
const handleValidation = (req, res, next) => {
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    return res.status(400).json({ error: 'Invalid input' }); // don't echo user input
  }
  next();
};

// --- Routes ---
app.get('/health', (_req, res) => {
  res.json({ status: 'ok' });
});

app.get(
  '/users',
  [query('id').optional().isInt({ min: 1 }).toInt()],
  handleValidation,
  (req, res, next) => {
    try {
      const users = [
        { id: 1, name: 'Alice', email: 'alice@example.com' },
        { id: 2, name: 'Bob', email: 'bob@example.com' },
      ];
      const result = req.query.id
        ? users.filter((u) => u.id === req.query.id)
        : users;
      res.json(result);
    } catch (err) {
      next(err);
    }
  }
);

// --- 404 handler ---
app.use((_req, res) => res.status(404).json({ error: 'Not found' }));

// --- Central error handler ---
// eslint-disable-next-line no-unused-vars
app.use((err, _req, res, _next) => {
  console.error(err); // log server-side only
  res.status(err.status || 500).json({ error: 'Internal server error' });
});

// --- Startup & graceful shutdown ---
const PORT = Number(process.env.PORT) || 3000;
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

const shutdown = (signal) => {
  console.log(`${signal} received, shutting down`);
  server.close(() => process.exit(0));
  setTimeout(() => process.exit(1), 10_000).unref();
};
